// ==========================================
// 🤖 LÓGICA SUB-WORKFLOW: GREGORIO (ASESOR)
// ==========================================

const items = $input.all();
const mergedData = Object.assign({}, ...items.map(i => i.json));

const datosParaSub = mergedData.datosParaSub || {};
const fase = datosParaSub.fase || 'INICIO'; 
let sessionId = mergedData.sessionId || datosParaSub.sessionId || '';
let chatInput = mergedData.chatInput || '';

let reply = '';
let options = [];
let ir_a_ia = false;
let accion_local = 'ASESOR_GREGORIO';

// 🚨 VALIDACIÓN DE ENTRADA: MENU o INICIO disparan el saludo
if (fase === 'MENU' || fase === 'INICIO') {

    // 🕰️ Obtener la hora actual asegurando la zona horaria correcta
    let opcionesHora = { timeZone: 'America/Argentina/Mendoza', hour: 'numeric', hour12: false };
    let horaActual = parseInt(new Intl.DateTimeFormat('es-AR', opcionesHora).format(new Date()));

    // 🌤️ Lógica del saludo
    let saludo = 'Buenos días';
    if (horaActual >= 12 && horaActual < 20) {
        saludo = 'Buenas tardes';
    } else if (horaActual >= 20 || horaActual < 6) {
        saludo = 'Buenas noches';
    }

    reply = `¡${saludo}! ¿En qué puedo ayudarlo? Al finalizar le voy a enviar una encuesta de satisfacción para permitirnos conocer su opinión y mejorar el servicio.`;

    options = [
        { label: "🔙 Volver al inicio", nodoId: "MAIN", trackingId: 100 }
    ];

    ir_a_ia = false;
    accion_local = 'SALUDO_INICIAL';
}
else {
    // Si la fase es distinta (ej: ESPERANDO_ASESOR), activamos la IA
    ir_a_ia = true;
    accion_local = 'CONSULTA_IA';
}

return [{
    json: {
        reply: reply,
        options: options,
        ir_a_ia: ir_a_ia,
        accion: accion_local,
        sessionId: sessionId,
        chatInput: chatInput, // Pasamos el mensaje del vecino al siguiente nodo
        fase: 'CHAT'
    }
}];

// ==========================================
// 🔄 RESTAURAR MENSAJE Y BOTONES
// ==========================================

// 1. Buscamos los datos que generó el nodo de lógica (antes de Oracle)
// CAMBIA 'Desarrollo Social' POR EL NOMBRE EXACTO DE TU NODO ANTERIOR
const datosOriginales = $('logica asesor').first().json; 

// 2. Devolvemos la respuesta visual (Texto + Botón Volver)
return [{
  json: {
    reply: datosOriginales.reply,
    options: datosOriginales.options
  }
}];

// 1. Recuperamos el historial antiguo del nodo Redis ('Leer_Historial')
let historialCrudo = $('Leer_Historial').first().json.propertyName;
let historial = [];

// Validamos si historialCrudo existe y qué formato tiene
if (historialCrudo) {
    if (typeof historialCrudo === 'string') {
        try {
            historial = JSON.parse(historialCrudo);
        } catch(e) {
            historial = []; // Si falla, arrancamos desde cero
        }
    } else if (Array.isArray(historialCrudo)) {
        historial = historialCrudo;
    }
}

// 2. Recuperamos los datos del flujo actual
const inputData = $input.first().json;

// ==========================================
// NUEVO: RECUPERAR MENSAJE DEL VECINO
// ==========================================
let inputReal = "";

try {
    // 1ro: Intentamos atrapar el mensaje limpio del nodo 'transcripción'
    inputReal = $('transcripción').first().json.mensaje;
} catch (e) {}

// 2do: Si no lo encontró ahí (o si tiene la etiqueta de audio falsa), buscamos en 'Edit Fields'
if (!inputReal || inputReal.includes("[Mensaje de voz enviado]")) {
    try {
        let textoEdit = $('set variables').first().json.mensaje;
        if (textoEdit && !textoEdit.includes("[Mensaje de voz enviado]")) {
            inputReal = textoEdit;
        }
    } catch (e) {}
}

// Limpiamos y preparamos el mensaje final
let mensajeUsuario = (inputReal && inputReal.trim() !== "") ? inputReal.trim() : "hola";

// ==========================================

// Recuperamos la respuesta de texto del bot
let respuestaBot = inputData.output || inputData.reply || inputData.mensaje || "";

// Recuperamos el audio generado (si el flujo pasó por el camino de arriba)
let audioBot = null;
try {
    audioBot = $('prepara audio').first().json.audio_respuesta || null;
} catch (e) {
    audioBot = null;
}

// 3. Añadimos la nueva interacción al array de memoria (A Redis solo va texto, nunca audio)
if (mensajeUsuario) {
    historial.push(`Vecino: ${mensajeUsuario}`);
}
if (respuestaBot) {
    historial.push(`Gregorio: ${respuestaBot}`);
}

// 4. CONTROL DE TOKENS: Limitamos a las últimas 10 líneas (5 interacciones)
if (historial.length > 10) {
    historial = historial.slice(-10);
}

// 5. Retornamos la memoria y empaquetamos TODO para el final
return [{
    json: {
        // Los tres puntos (...) "desparraman" todas las variables originales (sessionId, trackingId, etc.) 
        // para que no se pierdan en el camino hacia tu webhook final.
        ...inputData, 

        guardar_en_redis: historial, 
        value_texto: historial.join('\n'), 
        reply: respuestaBot,
        audio_respuesta: audioBot // Dejamos la variable lista para tu front-end
    }
}];

// 1. Obtenemos la respuesta de Gregorio
let textoOriginal = $input.first().json.output || "";
let textoParaChat = textoOriginal;
let botonesExtraidos = [];

// 2. Limpieza de bloques de código Markdown (por si la IA los agrega)
textoParaChat = textoParaChat.replace(/```json/gi, '').replace(/```/g, '');

// 3. ASPIRADORA SELECTIVA: Buscamos objetos que parezcan botones
// Esta regex busca patrones de { "label": ... }
const regexBotones = /\{\s*["']label["']\s*:[\s\S]*?\}/g;
let coincidencias = textoOriginal.match(regexBotones);

if (coincidencias) {
    coincidencias.forEach(jsonString => {
        // Borramos el JSON del texto del chat
        textoParaChat = textoParaChat.replace(jsonString, '');

        try {
            // Arreglamos comillas simples y parseamos
            let jsonArreglado = jsonString.replace(/'/g, '"');
            let objBoton = JSON.parse(jsonArreglado);
            botonesExtraidos.push(objBoton);
        } catch (e) {
            console.error("Error parseando botón individual:", e);
        }
    });
}

// 4. LIMPIEZA FINAL DEL TEXTO
// Quitamos corchetes sobrantes, comas huérfanas y espacios extra
textoParaChat = textoParaChat
    .replace(/\[\s*\]/g, '') // Quita [] vacíos
    .replace(/,\s*$/, '')    // Quita coma al final
    .replace(/\s+/g, ' ')    // Normaliza espacios
    .trim();

// 5. Si después de limpiar el texto quedó vacío, le ponemos un fallback 
// para que no aparezca la burbuja vacía
if (textoParaChat === "" && botonesExtraidos.length > 0) {
    textoParaChat = "Aquí tenés las opciones disponibles:";
}

// 6. Texto para el Audio (sin URLs ni etiquetas)
let textoParaAudio = textoParaChat
    .replace(/(?:https?|ftp):\/\/[\n\S]+/g, '')
    .replace(/<[^>]*>?/gm, '');

return [{
    json: {
        ...$input.first().json,
        respuesta_chat: textoParaChat,
        texto_limpio: textoParaAudio,
        opciones_botones: botonesExtraidos
    }
}];

