// 1. Recuperamos los datos originales con los que entró el vecino
const originalData = $('logica asesor').first().json;
let finalReply = "Lo siento, tuve un problema procesando la información.";

try {
    // 2. Intentamos sacar el texto limpio del Agente
    const agentNode = $('AI Agent').first();
    if (agentNode && agentNode.json && agentNode.json.output) {
        finalReply = agentNode.json.output;
    }
} catch (error) {}

// 3. Devolvemos el paquete EXACTO que espera tu sistema principal
return [{
    json: {
        reply: finalReply,
        options: [
            { label: "🔙 Volver al inicio", nodoId: "MAIN", trackingId: 100 }
        ],
        sessionId: originalData.sessionId,
        accion: "RESPUESTA_IA", // <-- Si tu orquestador usa otro nombre, cambialo acá
        tracking_actual: 205,   // <-- Agregamos el tracking_actual que usabas en Tasas
        fase: "CHAT"            // <-- Le avisamos que seguimos charlando
    }
}];

const input = $input.first().json;
// Buscamos la fase en la raíz o dentro de datosParaSub por seguridad
const faseActual = input.fase || (input.datosParaSub ? input.datosParaSub.fase : 'PEDIR_INMUEBLE'); 

// 🔍 Rescatamos el sessionId de forma ultra-segura para evitar caídas
let currentSessionId = '';
try {
    currentSessionId = $('Execute Workflow Trigger').first().json.sessionId || $('Execute Workflow Trigger').first().json.body.sessionId;
} catch (e) {
    currentSessionId = input.sessionId || (input.body ? input.body.sessionId : '');
}

let datosSub = {
    accion: "EXEC_SUB_TASAS",
    sessionId: currentSessionId, // <-- Inyectamos la sesión en la raíz
    body: {
        sessionId: currentSessionId // <-- Y adentro de body por las dudas
    }
};

// 🤖 Evaluamos la fase e inyectamos la nueva variable "origen_ia"
if (faseActual === 'PEDIR_INMUEBLE') {
    datosSub.proximoEstado = "ESPERANDO_INMUEBLE";
    datosSub.trackingId = 201;
    datosSub.datosParaSub = { 
        "fase": "PEDIR_INMUEBLE",
        "origen_ia": true // 🌟 Variable nueva para validar en el Logic Router
    };
} else {
    datosSub.proximoEstado = "ESPERANDO_COMERCIO";
    datosSub.trackingId = 202;
    datosSub.datosParaSub = { 
        "fase": "PEDIR_COMERCIO",
        "origen_ia": true // 🌟 Variable nueva para validar en el Logic Router
    };
}

return [{ json: datosSub }];

const input = $input.first().json;
let textoIA = input.output || '';

// 1. Limpiamos los bloques de código markdown si la IA los puso (```json ... ```)
if (textoIA.includes('```')) {
    textoIA = textoIA.replace(/```json/g, '').replace(/```/g, '').trim();
}

try {
    // 2. Intentamos parsear el texto limpio a un objeto real
    const objetoParseado = JSON.parse(textoIA.trim());

    return [{
        json: {
            reply: objetoParseado.reply !== undefined ? objetoParseado.reply : '',
            fase: objetoParseado.fase !== undefined ? objetoParseado.fase : 'CHAT',
            sessionId: input.sessionId || '' // Mantenemos la sesión activa
        }
    }];
} catch (e) {
    // Fallback: Si la IA devolvió texto plano común por error, lo mandamos al CHAT
    return [{
        json: {
            reply: textoIA,
            fase: 'CHAT',
            sessionId: input.sessionId || ''
        }
    }];
}

const inputData = $input.first().json;

// 1. Buscamos el audio (por si viene en audio_respuesta o en audio)
const audioCompleto = inputData.audio_respuesta || inputData.audio;

// 2. Si por algún motivo no hay audio, dejamos pasar el JSON tal cual para que el bot responda por texto
if (!audioCompleto) {
    return [{ json: inputData }];
}

// 3. Re-empaquetamos TODO junto. 
// Usamos ...inputData para conservar el 'reply', 'options', 'sessionId', etc.
return [{
    json: {
        ...inputData, 
        audio: audioCompleto,         // El script.js de tu web busca 'audio'
        audio_respuesta: audioCompleto // Lo dejamos también por si otro nodo lo busca
    }
}];

// NOTA: Eliminamos todo el bloque "binary: {}" a propósito. 
// Esto obliga al Webhook a responder con el texto JSON y no forzar una descarga de archivo.

// Dividimos el texto por los dobles saltos de línea que configuramos en el prompt
const fullText = $('Call \'Subworkflow - Asesor IA Nube').first().json.reply;
const paragraphs = fullText.split('\n\n').filter(p => p.trim() !== '');
// Devolvemos cada párrafo como un ítem individual para que n8n dispare el webhook varias veces
return paragraphs.map(p => {
  return {
    json: {
      reply: p.trim(),
      sessionId: $('Webhook Entrada').first().json.body.sessionId
    }
  };
});

const input = $input.first().json;
const respuestaOriginal = (input.output || input.reply || '').toString();

// 🎯 REGLA DE LIMPIEZA EXTREMA (Regex):
// Removemos los corchetes [ ] y todo lo que tengan adentro para no contar los botones.
// También aplicamos .trim() para quitar espacios fantasmas al principio y al final.
const textoLimpio = respuestaOriginal.replace(/\[[\s\S]*?\]/g, '').trim();

// 📊 Contamos los caracteres reales (aquí los espacios entre palabras SÍ cuentan)
const cantidadCaracteres = textoLimpio.length;

return [{
    json: {
        ...input,
        reply: respuestaOriginal, // Conservamos el texto largo intacto para entregárselo a la IA resumidora
        texto_medido_limpio: textoLimpio, // Por si querés auditar qué se midió
        cantidad_caracteres: cantidadCaracteres // 🌟 Tu nueva variable de control
    }
}];

